import React, { useEffect, useState, Fragment } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const API = 'https://pizza-story-backend-u6n0.onrender.com';

const STEPS = [
  { key: 'pending',        label: 'התקבלה',     icon: '📋' },
  { key: 'preparing',      label: 'בהכנה',       icon: '👨‍🍳' },
  { key: 'outForDelivery', label: 'בדרך',        icon: '🛵' },
  { key: 'completed',      label: 'הושלמה',      icon: '✅' },
];

function stepIndex(status) {
  const idx = STEPS.findIndex(s => s.key === status);
  return idx === -1 ? 0 : idx;
}

export default function OrderTracker() {
  const [order, setOrder] = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const auth = JSON.parse(localStorage.getItem('pizzaAuth') || '{}');

  const fetchOrder = () => {
    if (!auth.phone) return;
    axios
      .get(`${API}/api/orders/current/${auth.phone}`)
      .then(res => setOrder(res.data))
      .catch(() => setOrder(null))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    if (!auth.phone) { navigate('/login'); return; }
    fetchOrder();
    const id = setInterval(fetchOrder, 30000);
    return () => clearInterval(id);
  }, []);

  const currentStep = stepIndex(order?.status || 'pending');

  if (loading) {
    return (
      <div className="max-w-md mx-auto mt-20 text-center text-gray-400">
        <div className="text-5xl mb-4 animate-pulse">🍕</div>
        <p>טוען...</p>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto mt-0 pb-10">
      {/* Red Header */}
      <div className="flex items-center justify-between px-5 py-4 bg-tomato text-white">
        <h2 className="text-xl font-bold">מעקב הזמנה</h2>
        <button
          onClick={() => navigate('/')}
          className="bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-lg text-sm font-medium transition"
        >
          ← תפריט
        </button>
      </div>

      <div className="px-4 pt-5">
        {!order ? (
          <div className="text-center py-20 text-gray-400">
            <div className="text-6xl mb-4">🍕</div>
            <p className="text-lg mb-2">אין הזמנה פעילה כרגע</p>
            <p className="text-sm mb-6">ההזמנות האחרונות שלך יופיעו כאן</p>
            <button
              onClick={() => navigate('/')}
              className="bg-tomato text-white px-8 py-3 rounded-xl font-bold hover:bg-red-700 transition"
            >
              הזמן עכשיו
            </button>
          </div>
        ) : (
          <div className="bg-white rounded-2xl shadow-lg p-6">
            {/* Order summary row */}
            <div className="flex justify-between items-center mb-5 pb-4 border-b border-gray-100">
              <div>
                <p className="text-xs text-gray-400 mb-0.5">
                  הזמנה #{order.id?.slice(-6)}
                </p>
                <p className="font-bold text-2xl text-tomato">{order.total}₪</p>
              </div>
              <div className="text-left">
                <p className="text-xs text-gray-400">
                  {order.createdAt
                    ? new Date(order.createdAt).toLocaleTimeString('he-IL', {
                        hour: '2-digit',
                        minute: '2-digit',
                      })
                    : ''}
                </p>
                <p className="text-xs text-gray-500 mt-0.5 max-w-[130px] truncate">
                  {order.toppings?.join(', ') || 'ללא תוספות'}
                </p>
              </div>
            </div>

            {/* Progress Steps */}
            <div className="flex items-start my-6">
              {STEPS.map((step, idx) => {
                const done = idx <= currentStep;
                const lineActive = idx < currentStep;
                return (
                  <Fragment key={step.key}>
                    <div className="flex flex-col items-center" style={{ minWidth: 60 }}>
                      <div
                        className={`w-12 h-12 rounded-full flex items-center justify-center text-xl border-2 transition-all duration-500
                          ${done
                            ? 'bg-tomato border-tomato shadow-md'
                            : 'bg-white border-gray-200 text-gray-400'
                          }`}
                      >
                        {step.icon}
                      </div>
                      <span
                        className={`text-xs mt-2 font-medium text-center leading-tight
                          ${done ? 'text-tomato' : 'text-gray-400'}`}
                      >
                        {step.label}
                      </span>
                    </div>
                    {idx < STEPS.length - 1 && (
                      <div
                        className={`flex-1 h-0.5 mt-6 transition-all duration-500
                          ${lineActive ? 'bg-tomato' : 'bg-gray-200'}`}
                      />
                    )}
                  </Fragment>
                );
              })}
            </div>

            {/* Status message */}
            <div className="bg-orange-50 rounded-xl p-4 text-center mt-2">
              <p className="text-gray-700 font-medium">
                {order.status === 'pending' && '📋 ההזמנה שלך התקבלה! מועברת למטבח...'}
                {order.status === 'preparing' && '👨‍🍳 המטבח עובד על הפיצה שלך!'}
                {order.status === 'outForDelivery' && '🛵 הפיצה יצאה ובדרך אליך!'}
                {order.status === 'completed' && '✅ ההזמנה הושלמה! תיאבון 🍕'}
                {!order.status && '📋 ממתין לעדכון מהמטבח...'}
              </p>
            </div>

            <p className="text-xs text-center text-gray-400 mt-3">
              מתעדכן אוטומטית כל 30 שניות
            </p>
          </div>
        )}
      </div>
    </div>
  );
}
